import React from 'react';
import { motion } from 'framer-motion';
import { FaUniversity, FaMapMarkerAlt, FaLightbulb, FaUsers } from 'react-icons/fa';
import './About.css';

const About = () => {
  const highlights = [
    {
      icon: <FaUniversity />,
      title: "M.Sc. Mathematics",
      subtitle: "Ghent University, Belgium"
    },
    {
      icon: <FaMapMarkerAlt />,
      title: "Based in Belgium",
      subtitle: "Open to EU opportunities"
    },
    {
      icon: <FaLightbulb />,
      title: "10+ Years",
      subtitle: "Analytical Experience"
    },
    {
      icon: <FaUsers />,
      title: "Multi-Domain",
      subtitle: "Business, Finance, Healthcare"
    }
  ];

  return (
    <section id="about" className="about section">
      <div className="container">
        <motion.h2
          className="section-title"
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.5 }}
        >
          About Me
        </motion.h2>

        <div className="about-content">
          <motion.div
            className="about-text"
            initial={{ opacity: 0, x: -50 }}
            whileInView={{ opacity: 1, x: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.6 }}
          >
            <p>
              I architect <strong>Intelligent Systems</strong> at the intersection of 
              <span className="gradient-text"> mathematical foundations</span> and 
              <span className="gradient-text"> AI/ML engineering</span>. My approach combines 
              theoretical rigor from pure mathematics with practical machine learning to solve 
              high-stakes problems in Business, Finance, Healthcare, and Defense.
            </p>

            <p>
              Currently at <strong>Ghent University, Belgium</strong>, I'm developing computational 
              methods for <strong>Reducing Bias in Likelihood Ratio Tests for Structural Equation 
              Modelling</strong> — advancing how we distinguish true causal relationships from 
              statistical artifacts in complex, multi-domain datasets.
            </p>

            <p>
              With <strong>10+ years</strong> of analytical experience spanning education, 
              entrepreneurship, and data engineering, I bring a unique synthesis: deep mathematical 
              proofs, statistical rigor, production-ready ML systems, and business acumen to tackle 
              problems that demand both theoretical soundness and practical impact.
            </p>

            <div className="about-details">
              <div className="detail-item">
                <strong>🧠 Research Focus:</strong> Causal ML, SEM Bias Reduction, Neural-Symbolic AI, Deep Learning
              </div>
              <div className="detail-item">
                <strong>📍 Location Timeline:</strong> India (until Aug 2025) → Ghent, Belgium (Sep 2025 - Present)
              </div>
              <div className="detail-item">
                <strong>🌍 Languages:</strong> English (C2), Hindi (C2), Gujarati (Native), Dutch (Learning 🇧🇪)
              </div>
              <div className="detail-item">
                <strong>🔬 Academic Interest:</strong> Consciousness Studies, Mathematical Frameworks, Complex Systems
              </div>
            </div>
          </motion.div>

          <motion.div
            className="highlights-grid"
            initial={{ opacity: 0, x: 50 }}
            whileInView={{ opacity: 1, x: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.6 }}
          >
            {highlights.map((item, index) => (
              <motion.div
                key={index}
                className="highlight-card glow-box"
                whileHover={{ scale: 1.05 }}
                transition={{ type: 'spring', stiffness: 300 }}
              >
                <div className="highlight-icon">{item.icon}</div>
                <div className="highlight-title">{item.title}</div>
                <div className="highlight-subtitle">{item.subtitle}</div>
              </motion.div>
            ))}
          </motion.div>
        </div>
      </div>
    </section>
  );
};

export default About;
